# =========================
# EMAIL CONFIG (Titan SMTP)
# =========================
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
from datetime import datetime
import random, string

SMTP_SERVER   = "smtp.titan.email"
SMTP_PORT     = 465
SMTP_USER     = "noreply@umiclean.co"
SMTP_PASSWORD = "123pariS…"  # <-- tu contraseña de Titan aquí

def send_order_email(to_email, to_name, order_items, order_total, order_id):
    try:
        msg = MIMEMultipart("alternative")
        msg["Subject"] = f"✅ ¡Gracias por tu pedido UmiClean! #{order_id}"
        msg["From"]    = f"UmiClean <{SMTP_USER}>"
        msg["To"]      = to_email

        fecha = datetime.now().strftime("%d de %B de %Y, %I:%M %p")
        items_html = "".join([
            f"<tr><td style='padding:8px;border-bottom:1px solid #eee'>{it['name']}</td>"
            f"<td style='padding:8px;border-bottom:1px solid #eee;text-align:right'>x{it['qty']}</td>"
            f"<td style='padding:8px;border-bottom:1px solid #eee;text-align:right'>${it['total']:,} COP</td></tr>"
            for it in order_items
        ])

        html = f"""
        <div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">
          <div style="background:#0d2b52;padding:32px;text-align:center;border-radius:12px 12px 0 0">
            <h1 style="color:white;margin:0;font-size:2rem">UmiClean</h1>
            <p style="color:#00c9a7;margin:8px 0 0;font-size:1rem">Oxígeno Activo · Sin Cloro</p>
          </div>
          <div style="background:#f7f9fc;padding:32px;border-radius:0 0 12px 12px">
            <h2 style="color:#0d2b52">¡Gracias por tu compra, {to_name}! 🎉</h2>
            <p style="color:#555">Tu pedido fue recibido exitosamente. Nos pondremos en contacto contigo pronto para coordinar la entrega.</p>
            <div style="background:white;border-radius:10px;padding:20px;margin:20px 0;box-shadow:0 2px 8px rgba(0,0,0,.06)">
              <p style="margin:0 0 4px;font-size:.8rem;color:#888;text-transform:uppercase;letter-spacing:.1em">Número de pedido</p>
              <p style="margin:0;font-size:1.4rem;font-weight:700;color:#0d2b52">#{order_id}</p>
              <p style="margin:8px 0 0;font-size:.85rem;color:#888">{fecha}</p>
            </div>
            <table style="width:100%;border-collapse:collapse;margin:20px 0">
              <thead>
                <tr style="background:#0d2b52;color:white">
                  <th style="padding:10px;text-align:left;border-radius:8px 0 0 0">Producto</th>
                  <th style="padding:10px;text-align:right">Cant.</th>
                  <th style="padding:10px;text-align:right;border-radius:0 8px 0 0">Valor</th>
                </tr>
              </thead>
              <tbody>{items_html}</tbody>
              <tfoot>
                <tr>
                  <td colspan="2" style="padding:12px;font-weight:700;color:#0d2b52">TOTAL</td>
                  <td style="padding:12px;font-weight:700;color:#0d2b52;text-align:right">${order_total:,} COP</td>
                </tr>
              </tfoot>
            </table>
            <div style="background:#e8f5e9;border-left:4px solid #00c9a7;padding:16px;border-radius:0 8px 8px 0;margin:20px 0">
              <p style="margin:0;color:#2e7d32;font-size:.9rem">💬 <strong>Próximo paso:</strong> Te contactaremos por WhatsApp al número que nos dejaste para coordinar el pago y la entrega.</p>
            </div>
            <p style="text-align:center;color:#888;font-size:.8rem;margin-top:24px">
              © 2025 UmiClean · Bogotá, Colombia · <a href="https://umiclean.co" style="color:#0d2b52">umiclean.co</a>
            </p>
          </div>
        </div>
        """

        msg.attach(MIMEText(html, "html"))
        with smtplib.SMTP_SSL(SMTP_SERVER, SMTP_PORT) as s:
            s.login(SMTP_USER, SMTP_PASSWORD)
            s.sendmail(SMTP_USER, to_email, msg.as_string())
        return True
    except Exception as e:
        print(f"Email error: {e}")
        return False


