THANKS_HTML = """
<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1"/>
  <title>¡Gracias por tu compra! · UmiClean</title>
  <link href="https://fonts.googleapis.com/css2?family=Syne:wght@700;800;900&family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet"/>
  <style>
    *{margin:0;padding:0;box-sizing:border-box}
    body{font-family:"Inter",sans-serif;background:#f7f9fc;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:20px}
    .card{background:white;border-radius:24px;box-shadow:0 20px 60px rgba(13,43,82,.12);max-width:520px;width:100%;overflow:hidden;animation:pop .5s ease}
    @keyframes pop{from{opacity:0;transform:scale(.95)}to{opacity:1;transform:scale(1)}}
    .top{background:linear-gradient(135deg,#0d2b52,#1a4080);padding:40px 32px;text-align:center}
    .checkmark{width:72px;height:72px;background:#00c9a7;border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 20px;font-size:2rem;box-shadow:0 8px 24px rgba(0,201,167,.4)}
    .top h1{font-family:"Syne",sans-serif;color:white;font-size:1.8rem;margin-bottom:8px}
    .top p{color:rgba(255,255,255,.7);font-size:.95rem}
    .body{padding:32px}
    .order-id{background:#f0f4ff;border-radius:12px;padding:16px;text-align:center;margin-bottom:24px}
    .order-id .label{font-size:.75rem;color:#888;text-transform:uppercase;letter-spacing:.15em;margin-bottom:4px}
    .order-id .num{font-family:"Syne",sans-serif;font-size:1.6rem;font-weight:800;color:#0d2b52}
    .order-id .date{font-size:.82rem;color:#888;margin-top:4px}
    .info{background:#e8f5f0;border-left:3px solid #00c9a7;padding:14px 16px;border-radius:0 10px 10px 0;margin-bottom:24px;font-size:.9rem;color:#2e7d32;line-height:1.6}
    .btn{display:block;background:#25d366;color:white;text-align:center;padding:16px;border-radius:999px;font-weight:700;font-size:1rem;text-decoration:none;box-shadow:0 8px 20px rgba(37,211,102,.3);margin-bottom:12px}
    .btn2{display:block;background:#0d2b52;color:white;text-align:center;padding:16px;border-radius:999px;font-weight:700;font-size:1rem;text-decoration:none}
    .footer{text-align:center;color:#aaa;font-size:.8rem;margin-top:20px}
  </style>
</head>
<body>
  <div class="card">
    <div class="top">
      <div class="checkmark">✅</div>
      <h1>¡Pedido recibido!</h1>
      <p>Gracias por confiar en UmiClean 🫧</p>
    </div>
    <div class="body">
      <div class="order-id">
        <div class="label">Número de pedido</div>
        <div class="num">#{{ order_id }}</div>
        <div class="date">{{ fecha }}</div>
      </div>
      <div class="info">
        💬 <strong>Próximo paso:</strong> Te contactaremos por WhatsApp para coordinar el pago y la entrega. ¡Revisa tus mensajes!
      </div>
      <a href="https://wa.me/{{ whatsapp_number }}" class="btn" target="_blank">💬 Escribirnos por WhatsApp</a>
      <a href="/" class="btn2">← Volver a la tienda</a>
      <div class="footer">© 2025 UmiClean · umiclean.co</div>
    </div>
  </div>
</body>
</html>
"""

@app.route("/gracias")
def gracias():
    order_id = ''.join(random.choices(string.ascii_uppercase + string.digits, k=8))
    fecha = datetime.now().strftime("%d/%m/%Y · %I:%M %p")
    return render_template_string(
        THANKS_HTML,
        order_id=order_id,
        fecha=fecha,
        whatsapp_number=WHATSAPP_NUMBER
    )



@app.route("/pedido", methods=["POST"])
def pedido():
    from flask import request, jsonify
    import json, random, string
    from datetime import datetime

    data = request.get_json()
    if not data:
        return jsonify({"ok": False}), 400

    ref        = data.get("ref", "SIN-REF")
    cliente    = data.get("cliente", {})
    items      = data.get("items", [])
    total_val  = data.get("total", 0)
    envio      = data.get("envio", 0)
    fecha      = datetime.now().strftime("%d/%m/%Y %I:%M %p")

    nombre    = cliente.get("nombre", "")
    celular   = cliente.get("celular", "")
    email     = cliente.get("email", "")
    direccion = cliente.get("direccion", "")
    ciudad    = cliente.get("ciudad", "")

    # Build items HTML
    items_html = "".join([
        f"<tr><td style='padding:8px;border-bottom:1px solid #eee'>{it.get('name','')}</td>"
        f"<td style='padding:8px;border-bottom:1px solid #eee;text-align:right'>x{it.get('qty',1)}</td>"
        f"<td style='padding:8px;border-bottom:1px solid #eee;text-align:right'>${it.get('price',0)*it.get('qty',1):,} COP</td></tr>"
        for it in items
    ])

    # 1. Email to CLIENT
    html_cliente = f"""
    <div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">
      <div style="background:#0d2b52;padding:32px;text-align:center;border-radius:12px 12px 0 0">
        <h1 style="color:white;margin:0;font-size:2rem">UmiClean</h1>
        <p style="color:#00c9a7;margin:8px 0 0">Oxígeno Activo · Sin Cloro</p>
      </div>
      <div style="background:#f7f9fc;padding:32px;border-radius:0 0 12px 12px">
        <h2 style="color:#0d2b52">¡Gracias por tu compra, {nombre}! 🎉</h2>
        <p style="color:#555">Tu pago fue procesado exitosamente. Te contactaremos pronto para confirmar el envío.</p>
        <div style="background:white;border-radius:10px;padding:20px;margin:20px 0">
          <p style="margin:0 0 4px;font-size:.8rem;color:#888;text-transform:uppercase">Referencia</p>
          <p style="margin:0;font-size:1.3rem;font-weight:700;color:#0d2b52">#{ref}</p>
          <p style="margin:8px 0 0;font-size:.85rem;color:#888">{fecha}</p>
        </div>
        <div style="background:#e8f5e9;border-left:4px solid #00c9a7;padding:16px;border-radius:0 8px 8px 0;margin:16px 0">
          <p style="margin:0;color:#2e7d32;font-size:.9rem"><strong>📍 Dirección de envío:</strong><br>{direccion}, {ciudad}<br>📱 {celular}</p>
        </div>
        <table style="width:100%;border-collapse:collapse;margin:20px 0">
          <thead><tr style="background:#0d2b52;color:white">
            <th style="padding:10px;text-align:left">Producto</th>
            <th style="padding:10px;text-align:right">Cant.</th>
            <th style="padding:10px;text-align:right">Valor</th>
          </tr></thead>
          <tbody>{items_html}</tbody>
          <tfoot><tr>
            <td colspan="2" style="padding:12px;font-weight:700;color:#0d2b52">TOTAL PAGADO</td>
            <td style="padding:12px;font-weight:700;color:#0d2b52;text-align:right">${total_val:,} COP</td>
          </tr></tfoot>
        </table>
        <p style="text-align:center;color:#888;font-size:.8rem;margin-top:24px">© 2025 UmiClean · umiclean.co</p>
      </div>
    </div>"""

    # 2. Email to YOU (noreply) — notification with full order details
    items_txt = "\n".join([f"- {it.get('name','')} x{it.get('qty',1)} = ${it.get('price',0)*it.get('qty',1):,} COP" for it in items])
    html_admin = f"""
    <div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;background:#fff;padding:32px;border-radius:12px;border:2px solid #0d2b52">
      <h2 style="color:#0d2b52">🛒 Nuevo Pedido UmiClean</h2>
      <p style="color:#555;font-size:.9rem">Referencia: <strong>{ref}</strong> · {fecha}</p>
      <hr style="border:none;border-top:1px solid #eee;margin:16px 0"/>
      <h3 style="color:#0d2b52;margin-bottom:8px">Cliente</h3>
      <p style="margin:4px 0;color:#333">👤 {nombre}</p>
      <p style="margin:4px 0;color:#333">📱 {celular}</p>
      <p style="margin:4px 0;color:#333">✉️ {email}</p>
      <p style="margin:4px 0;color:#333">📍 {direccion}, {ciudad}</p>
      <hr style="border:none;border-top:1px solid #eee;margin:16px 0"/>
      <h3 style="color:#0d2b52;margin-bottom:8px">Productos</h3>
      <table style="width:100%;border-collapse:collapse">
        <thead><tr style="background:#0d2b52;color:white">
          <th style="padding:8px;text-align:left">Producto</th>
          <th style="padding:8px;text-align:right">Cant.</th>
          <th style="padding:8px;text-align:right">Valor</th>
        </tr></thead>
        <tbody>{items_html}</tbody>
      </table>
      <p style="margin-top:16px;font-size:1.1rem;font-weight:700;color:#0d2b52">TOTAL: ${total_val:,} COP · Envío: ${"GRATIS" if envio==0 else f"{envio:,} COP"}</p>
      <hr style="border:none;border-top:1px solid #eee;margin:16px 0"/>
      <a href="https://wa.me/57{celular}?text=Hola+{nombre.replace(" ","+")},+tu+pedido+UmiClean+%23{ref}+fue+confirmado+y+est%C3%A1+en+camino+%F0%9F%9A%9A+%C2%A1Gracias+por+tu+compra!" 
         style="display:inline-block;background:#25d366;color:white;padding:14px 24px;border-radius:999px;font-weight:700;text-decoration:none;margin-top:8px">
        💬 Escribirle por WhatsApp
      </a>
    </div>"""

    # Send emails
    try:
        send_order_email(email, nombre, items, total_val, ref)
    except Exception as e:
        print(f"Error email cliente: {e}")

    try:
        import smtplib
        from email.mime.multipart import MIMEMultipart
        from email.mime.text import MIMEText
        msg2 = MIMEMultipart("alternative")
        msg2["Subject"] = f"🛒 Nuevo Pedido #{ref} — {nombre} — ${total_val:,} COP"
        msg2["From"] = f"UmiClean <{SMTP_USER}>"
        msg2["To"] = SMTP_USER
        msg2.attach(MIMEText(html_admin, "html"))
        with smtplib.SMTP_SSL(SMTP_SERVER, SMTP_PORT) as s:
            s.login(SMTP_USER, SMTP_PASSWORD)
            s.sendmail(SMTP_USER, SMTP_USER, msg2.as_string())
    except Exception as e:
        print(f"Error email admin: {e}")

    return jsonify({"ok": True, "ref": ref})


@app.route("/portafolio")
def portafolio():
    import os
    pdf_path = os.path.join(os.path.dirname(__file__), "UmiClean_Portafolio_v8.pdf")
    if os.path.exists(pdf_path):
        from flask import send_file
        return send_file(pdf_path, as_attachment=True, download_name="UmiClean_Portafolio.pdf")
    return redirect("/")


if __name__ == "__main__":
    app.run(debug=True, host="127.0.0.1", port=5000)
